pipeline.evaluate:
(() => {
  const items = [];
  document.querySelectorAll('item').forEach(el => {
    let title = el.querySelector('title')?.textContent?.trim() || '';
    const link = el.querySelector('link')?.textContent?.trim() || '';
    const pubDate = el.querySelector('pubDate')?.textContent?.trim() || '';
    let source = el.querySelector('source')?.textContent?.trim() || '';
    if (!source) {
      const idx = title.lastIndexOf(' - ');
      if (idx !== -1) {
        source = title.slice(idx + 3);
        title = title.slice(0, idx);
      }
    }
    items.push({ title, source, date: pubDate, url: link });
  });
  return items;
})()
